1204 /// Helper to keep track of a condition and if it should be treated as negated
1205 /// for reproducer construction.
1206 /// Pred == Predicate::BAD_ICMP_PREDICATE indicates that this entry is a
1207 /// placeholder to keep the ReproducerCondStack in sync with DFSInStack.
1208 struct ReproducerEntry {
1209   ICmpInst::Predicate Pred;
1210   Value *LHS;
1211   Value *RHS;
1212 
1213   ReproducerEntry(ICmpInst::Predicate Pred, Value *LHS, Value *RHS)
1214       : Pred(Pred), LHS(LHS), RHS(RHS) {}
1215 };
1216 } // namespace
